I have a function that builds the system prompt with if-statements based on mode and model. Migrate it to promptbook so the conditionals become rules, not code.

```ts
function buildSystem(opts: { mode: 'terse' | 'warm'; model: 'gpt' | 'claude' }) {
  let s = 'You are a customer support assistant. ';
  if (opts.mode === 'terse') s += 'Be terse and direct. ';
  else s += 'Be warm and welcoming. ';
  if (opts.model === 'gpt') s += 'Reply as JSON: { "reply": "..." }';
  else s += 'Reply with XML: <reply>...</reply>';
  return s;
}
```

